    ) THEN
        RAISE EXCEPTION 'python_default deployment is not running in Warren inventory';
    END IF;
END
$$;

DO $$
DECLARE
    result jsonb;
BEGIN
    PERFORM rvbbit.create_python_env(
        env_name => 'acceptance_python_env',
        python_version => '3.12',
        requirements => ARRAY[]::text[],
        runtime_name => 'python_default',
        timeout_ms => 3000
    );
    PERFORM rvbbit.create_python_handler(
        handler_name => 'acceptance_python_sla',
        env_name => 'acceptance_python_env',
        code => $code$
def run(inputs):
    tier = str(inputs.get("tier") or "standard").lower()
    age_hours = int(inputs.get("age_hours") or 0)
    breached = age_hours > 24
    priority = "urgent" if tier == "enterprise" and breached else "standard"
    return {"priority": priority, "breached": breached, "age_hours": age_hours}
$code$,
        entrypoint => 'run',
        description => 'Acceptance test handler for Warren-managed CPython runtime'
    );
    PERFORM rvbbit.create_operator(
        op_name => 'acceptance_python_sla',
        op_arg_names => ARRAY['tier','age_hours'],
        op_arg_types => ARRAY['text','text'],
        op_return_type => 'jsonb',
        op_parser => 'json',
        op_steps => $steps$[
          {
            "name": "score",
            "kind": "python",
            "env": "acceptance_python_env",
            "handler": "acceptance_python_sla",
            "inputs": {
              "tier": "{{ inputs.tier }}",
              "age_hours": "{{ inputs.age_hours }}"
            }
          }
        ]$steps$::jsonb
    );
    SELECT rvbbit.acceptance_python_sla('enterprise', '31') INTO result;
    IF jsonb_typeof(result) <> 'object'
       OR result->>'priority' <> 'urgent'
       OR coalesce((result->>'breached')::boolean, false) IS DISTINCT FROM true THEN
        RAISE EXCEPTION 'unexpected CPython operator result: %', result;
    END IF;
END
$$;

DO $$
DECLARE
    mismatches integer;
BEGIN
    CREATE TEMP TABLE warren_echo_cases (
        case_id integer,
        note text,
        expected text
    ) ON COMMIT DROP;

    INSERT INTO warren_echo_cases(case_id, note, expected) VALUES
        (1, 'refund request after delayed shipment', 'refund request after delayed shipment'),
        (2, 'warehouse damaged item needs replacement', 'warehouse damaged item needs replacement'),
        (3, 'vip customer asks for invoice correction', 'vip customer asks for invoice correction');

    SELECT count(*)
    INTO mismatches
    FROM (
        SELECT
            note,
            expected,
            rvbbit.warren_smoke_echo(note)->>'echo' AS got
        FROM warren_echo_cases
    ) checked
    WHERE got IS DISTINCT FROM expected;

    IF mismatches <> 0 THEN
        RAISE EXCEPTION 'warren_smoke_echo mismatches: %', mismatches;
    END IF;
END
$$;

DO $$
DECLARE
    probe jsonb;
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM rvbbit.backend_health
        WHERE name = 'warren_smoke_echo'
    ) THEN
        RAISE EXCEPTION 'warren_smoke_echo backend is not registered';
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM rvbbit.warren_inventory
        WHERE backend_name = 'warren_smoke_echo'
          AND deployment_status = 'running'
    ) THEN
        RAISE EXCEPTION 'warren_smoke_echo deployment is not running in Warren inventory';
    END IF;

    probe := rvbbit.backend_probe('warren_smoke_echo');
    IF coalesce((probe->>'ok')::boolean, false) IS DISTINCT FROM true THEN
        RAISE EXCEPTION 'warren_smoke_echo backend probe failed: %', probe;
    END IF;
END
$$;

